import { createClient } from '@supabase/supabase-js'

export class SessionStore {
  private supabase = createClient(
    process.env.SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )

  async updateContactName(
    tenantId: string,
    phoneNumber: string,
    contactData: {
      savedName?: string
      pushName?: string
      verifiedName?: string
    }
  ) {
    // Determine best name using WhatsApp hierarchy
    const bestName = contactData.savedName || 
                    contactData.verifiedName || 
                    contactData.pushName || 
                    phoneNumber

    // Update conversation contact_name
    const { error } = await this.supabase
      .from('conversations')
      .upsert({
        tenant_id: tenantId,
        phone_number: phoneNumber,
        contact_name: bestName,
        updated_at: new Date().toISOString()
      }, {
        onConflict: 'tenant_id,phone_number',
        ignoreDuplicates: false
      })

    if (error) {
      console.error('Failed to update contact name:', error)
    }

    // Also store raw contact data for reference
    const { error: contactError } = await this.supabase
      .from('contact_details')
      .upsert({
        tenant_id: tenantId,
        phone_number: phoneNumber,
        saved_name: contactData.savedName,
        push_name: contactData.pushName,
        verified_name: contactData.verifiedName,
        updated_at: new Date().toISOString()
      }, {
        onConflict: 'tenant_id,phone_number'
      })

    return { bestName, error: contactError }
  }

  async getContactName(tenantId: string, phoneNumber: string): Promise<string> {
    // First try to get from contact_details with hierarchy
    const { data: contactDetails } = await this.supabase
      .from('contact_details')
      .select('saved_name, push_name, verified_name')
      .eq('tenant_id', tenantId)
      .eq('phone_number', phoneNumber)
      .single()

    if (contactDetails) {
      return contactDetails.saved_name || 
             contactDetails.verified_name || 
             contactDetails.push_name || 
             phoneNumber
    }

    // Fallback to conversation contact_name
    const { data: conversation } = await this.supabase
      .from('conversations')
      .select('contact_name')
      .eq('tenant_id', tenantId)
      .eq('phone_number', phoneNumber)
      .single()

    return conversation?.contact_name || phoneNumber
  }
}
