  // 2. Verify tenant ownership
  const { data: tenant } = await supabase
    .from('tenants')
    .select('id')
    .eq('id', params.tenantId)
    .eq('user_id', user.id)  // CRITICAL: Check ownership
    .single();

  if (!tenant) {
