  const session = getSession(tenantId);  // Must validate tenant owns this session
  if (!session) {
    throw new Error(`No WhatsApp session for tenant ${tenantId}`);
  }

  // 3. Fetch from WhatsApp and save with tenant context
  const contact = await session.socket.fetchContacts([phoneNumber]);
  if (contact[0]) {
    await saveContactMetadata(tenantId, phoneNumber, {
      savedName: contact[0].name,
      pushName: contact[0].pushname
    });
  }

  return {
    savedName: contact[0]?.name,
    pushName: contact[0]?.pushname
  };
}
